import { db } from "../firebase.config.ts";
import {
  collection,
  addDoc,
  getDocs,
  query,
  where,
  serverTimestamp,
} from "firebase/firestore";

// Firestore Collection: "schemes"
// Document ID: auto-generated

export interface SchemeDocument {
  name: string;                             // required
  ministry: string;                         // default: ''
  category: string;                         // default: ''
  description: string;                      // default: ''
  eligibilityCriteria: Record<string, any>; // default: {}
  benefits: string;                         // default: ''
  deadline: string | null;                  // ISO string or null
  maxIncome: number | null;                 // default: null
  disabilityTypes: string[];                // default: []
  educationRequired: string;                // default: ''
  isActive: boolean;                        // default: true
  applyLink: string;                        // default: ''
  documents: string[];                      // required documents list
  icon: string;                             // icon name string
  source: string;                           // default: ''
  publishDate: string;                      // default: ''
  createdAt: any;                           // serverTimestamp()
}

// Add a scheme (Admin only)
export const addScheme = async (schemeData: Omit<SchemeDocument, "createdAt">) => {
  const schemesRef = collection(db, "schemes");
  await addDoc(schemesRef, { ...schemeData, createdAt: serverTimestamp() });
};

// Get all active schemes (public read)
export const getActiveSchemes = async () => {
  const schemesRef = collection(db, "schemes");
  const q = query(schemesRef, where("isActive", "==", true));
  const snap = await getDocs(q);
  return snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as SchemeDocument & { id: string }));
};

