// ── Seed Function ─────────────────────────────────────────────────────────────
// Run this ONCE to populate Firestore with all scheme listings
// e.g., call seedSchemes() from an admin page or a one-time script
export const seedSchemes = async () => {
  const schemesRef = collection(db, "schemes");
  const results = await Promise.allSettled(
    schemesData.map((scheme) =>
      addDoc(schemesRef, { ...scheme, createdAt: serverTimestamp() })
    )
  );

  const succeeded = results.filter((r) => r.status === "fulfilled").length;
  const failed = results.filter((r) => r.status === "rejected").length;

  console.log(`✅ Seeded ${succeeded} schemes successfully.`);
  if (failed > 0) console.warn(`⚠️ ${failed} schemes failed to seed.`);
};